import React, { useState, useEffect } from "react";
import { Link, NavLink } from "react-router-dom";
import { Menu, X, Globe, ArrowUpRight } from "lucide-react";
import { useLang } from "../i18n/LanguageContext";
import {
  DropdownMenu,
  DropdownMenuContent,
  DropdownMenuItem,
  DropdownMenuTrigger,
} from "./ui/dropdown-menu";

export default function Navbar() {
  const { lang, setLang, t } = useLang();
  const [open, setOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    let ticking = false;
    const onScroll = () => {
      if (ticking) return;
      ticking = true;
      requestAnimationFrame(() => {
        setScrolled((prev) => {
          const next = window.scrollY > 20;
          return prev === next ? prev : next;
        });
        ticking = false;
      });
    };
    window.addEventListener("scroll", onScroll, { passive: true });
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  const closeMenu = () => setOpen(false);

  const links = [
    { to: "/logistics", label: t.nav.logistics, id: "logistics" },
    { to: "/individual-software", label: t.nav.individualSoftware, id: "individual-software" },
    { to: "/travel", label: t.nav.travel, id: "travel" },
    { to: "/about", label: t.nav.about, id: "about" },
    { to: "/contact", label: t.nav.contact, id: "contact" },
  ];

  return (
    <header
      data-testid="main-navbar"
      className={`fixed top-0 left-0 right-0 z-50 transition-colors duration-300 ${
        scrolled
          ? "bg-white/95 border-b border-zinc-200 shadow-sm"
          : "bg-white/80 border-b border-transparent"
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 md:px-12">
        <div className="flex items-center justify-between h-20 md:h-24 gap-4">
          {/* Logo */}
          <Link
            to="/"
            data-testid="navbar-logo-link"
            className="flex min-w-0 items-center gap-3 group shrink-0"
          >
            <img
              src={`${process.env.PUBLIC_URL}/assets/dubas-logo.png`}
              alt="DUBAS GMBH"
              className="h-14 sm:h-16 md:h-20 w-auto max-w-[310px] object-contain"
            />
          </Link>

          {/* Desktop nav */}
          <nav className="hidden xl:flex items-center gap-1">
            {links.map((l) => (
              <NavLink
                key={l.id}
                to={l.to}
                end={l.to === "/"}
                data-testid={`nav-link-${l.id}`}
                className={({ isActive }) =>
                  `relative px-3 py-2 text-sm font-medium transition-colors whitespace-nowrap ${
                    isActive ? "nav-gradient-active" : "text-zinc-600 nav-gradient-hover"
                  }`
                }
              >
                {({ isActive }) => (
                  <>
                    {l.label}
                    {isActive && (
                      <span className="absolute left-3 right-3 -bottom-1 h-[2px] bg-gradient-brand rounded-full" />
                    )}
                  </>
                )}
              </NavLink>
            ))}
          </nav>

          {/* Right actions */}
          <div className="flex items-center gap-1 sm:gap-2">
            <DropdownMenu>
              <DropdownMenuTrigger
                data-testid="language-toggle-trigger"
                className="flex items-center gap-1.5 px-3 py-2 text-xs font-medium text-zinc-700 hover:text-zinc-900 border border-zinc-200 hover:border-blue-500/40 transition-colors uppercase tracking-wider"
              >
                <Globe className="h-3.5 w-3.5" />
                {lang}
              </DropdownMenuTrigger>
              <DropdownMenuContent
                align="end"
                className="bg-white border-zinc-200 text-zinc-900 min-w-[120px] rounded-none shadow-lg"
              >
                <DropdownMenuItem
                  data-testid="lang-option-de"
                  onClick={() => setLang("de")}
                  className="cursor-pointer focus:bg-blue-600/10 focus:text-zinc-900 rounded-none"
                >
                  <span className="mr-2">DE</span>
                  <span className="text-zinc-500 text-xs">Deutsch</span>
                </DropdownMenuItem>
                <DropdownMenuItem
                  data-testid="lang-option-en"
                  onClick={() => setLang("en")}
                  className="cursor-pointer focus:bg-blue-600/10 focus:text-zinc-900 rounded-none"
                >
                  <span className="mr-2">EN</span>
                  <span className="text-zinc-500 text-xs">English</span>
                </DropdownMenuItem>
              </DropdownMenuContent>
            </DropdownMenu>

            <Link
              to="/contact"
              data-testid="navbar-cta-button"
              className="hidden md:inline-flex items-center gap-2 px-5 py-2.5 text-sm font-medium bg-gradient-brand text-white hover:opacity-90 transition-opacity shadow-sm"
            >
              {t.nav.cta}
              <ArrowUpRight className="h-4 w-4" />
            </Link>

            <button
              data-testid="mobile-menu-toggle"
              onClick={() => setOpen((v) => !v)}
              className="xl:hidden p-2 text-zinc-900"
              aria-label="Toggle menu"
            >
              {open ? <X className="h-6 w-6" /> : <Menu className="h-6 w-6" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile menu */}
      {open && (
        <div
          data-testid="mobile-menu"
          className="xl:hidden bg-white border-t border-zinc-200 shadow-md"
        >
          <nav className="max-w-7xl mx-auto px-4 sm:px-6 py-5 flex flex-col gap-1">
            {links.map((l) => (
              <NavLink
                key={l.id}
                to={l.to}
                end={l.to === "/"}
                onClick={closeMenu}
                data-testid={`mobile-nav-link-${l.id}`}
                className={({ isActive }) =>
                  `px-3 py-3 text-sm font-medium border-l-2 transition-colors ${
                    isActive
                      ? "border-blue-500 nav-gradient-active"
                      : "border-transparent text-zinc-600 nav-gradient-hover hover:border-blue-400"
                  }`
                }
              >
                {l.label}
              </NavLink>
            ))}
            <Link
              to="/contact"
              onClick={closeMenu}
              data-testid="mobile-cta-button"
              className="mt-4 inline-flex items-center justify-center gap-2 px-5 py-3 text-sm font-medium bg-gradient-brand text-white"
            >
              {t.nav.cta}
              <ArrowUpRight className="h-4 w-4" />
            </Link>
          </nav>
        </div>
      )}
    </header>
  );
}
