import React from "react";
import { motion } from "framer-motion";

const baseTransition = {
  duration: 0.7,
  ease: [0.22, 1, 0.36, 1],
};

export const FadeUp = ({
  children,
  delay = 0,
  className = "",
  amount = 0.2,
  testId,
}) => (
  <motion.div
    data-testid={testId}
    className={className}
    initial={{ opacity: 0, y: 28 }}
    whileInView={{ opacity: 1, y: 0 }}
    viewport={{ once: true, amount }}
    transition={{ ...baseTransition, delay }}
  >
    {children}
  </motion.div>
);

export const FadeIn = ({
  children,
  delay = 0,
  className = "",
  amount = 0.2,
}) => (
  <motion.div
    className={className}
    initial={{ opacity: 0 }}
    whileInView={{ opacity: 1 }}
    viewport={{ once: true, amount }}
    transition={{ ...baseTransition, delay }}
  >
    {children}
  </motion.div>
);

export const StaggerGroup = ({ children, className = "", delayStep = 0.08 }) => (
  <motion.div
    className={className}
    initial="hidden"
    whileInView="visible"
    viewport={{ once: true, amount: 0.15 }}
    variants={{
      hidden: {},
      visible: {
        transition: { staggerChildren: delayStep, delayChildren: 0.05 },
      },
    }}
  >
    {children}
  </motion.div>
);

export const StaggerItem = ({ children, className = "" }) => (
  <motion.div
    className={className}
    variants={{
      hidden: { opacity: 0, y: 24 },
      visible: {
        opacity: 1,
        y: 0,
        transition: baseTransition,
      },
    }}
  >
    {children}
  </motion.div>
);
